window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2007>1","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Which of the following agricultural raw materials would a glue-processing industry require?","images":[],"options":{"A":"Cotton","B":"Coconut","C":"Cassava","D":"Kola"},"answer":"C","explanation":"Cassava starch is used for making adhesives, for holding two surfaces in place, a major product of glue-processing industry.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>2","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Perishability of farm produce can be minimized through","images":[],"options":{"A":"modification of the crop genetic composition","B":"adoption of continuous cropping system","C":"reducing water supply to growing crops","D":"use of machines to harvest crops"},"answer":"A","explanation":"The perishability of farm produce can be minimized through modification of the crop genetic composition. This involves adding a specific stretch of DNA or altering the genetic make up of a crop, giving it a new or different characteristic.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>3","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"In which of the following activities is land not used for agricultural purposes?","images":[],"options":{"A":"Afforestation","B":"Mining","C":"Ranching","D":"Fish farming"},"answer":"B","explanation":"Mining is the extraction of minerals and important elements from the earth. It should be noted that although mining is not an agricultural process, land is used.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>4","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"Which of the following statements about farm settlement schemes is false? They are set-up","images":[],"options":{"A":"to encourage young people to take up farming","B":"to provide employment for young school leavers","C":"to develop rural infrastructure","D":"for research and publicity"},"answer":"D","explanation":"For research and publicity: Farm settlement schemes are primarily to promote rural development; also to increase the standard of living of rural communities dwellers.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>5","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Water-logged soils impede good crop growth and development because","images":[],"options":{"A":"the fibrous roots are destroyed","B":"crop roots are deprived of sufficient oxygen","C":"excessive water stops root growth","D":"soil around roots become too cold for root growth"},"answer":"B","explanation":"Water-logged soils impede good crop growth and development because crop roots are deprived of sufficient oxygen. Water logged soils are soils with too much water, this water fills tiny spaces in the root, thereby cutting off oxygen to the root.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>6","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The relative proportion of each fraction of soil in a soil sample determines its","images":[],"options":{"A":"texture","B":"structure","C":"profile","D":"catena"},"answer":"A","explanation":"The relative proportion of each fraction of soil in a sample of soil determines its texture.  Texture: Soil texture classification involves grouping of soil classes based on their physical texture, these soil classes are grouped into different proportions.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>7","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following materials cannot be used for liming?","images":[],"options":{"A":"Gypsum","B":"Basic slag","C":"Chalk","D":"Urea"},"answer":"D","explanation":"Liming involves the application of calcium and magnesium rich materials in various forms to soil. Urea is a Nitrogen compound.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>8","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Which of the following statements about soil water is true?","images":[],"options":{"A":"Crops wilt when gravitational water has drained off","B":"Capillary water drains off after rainfall","C":"A soil with high water table is best for farming","D":"Crops utilize capillary water in the soil"},"answer":"D","explanation":"Crops utilize capillary water in the soil  Capillary water is the water that is left in the soil after gravitational water is drained out, making it available for utilization by crops.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>9","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following soil elements becomes readily available at pH values above 8??","images":[],"options":{"A":"Molybdenum","B":"Manganese","C":"Zinc","D":"Aluminium"},"answer":"A","explanation":"Most nutrients especially micronutrients are available at acidic pH [less than 7] except molybdenum which is more available at pH values above 8.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2007>10","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Micro-nutrients are likely to be deficient in","images":[],"options":{"A":"cleared virgin forest soils","B":"soils with high organic matter","C":"fine textured soil","D":"soils with low pH"},"answer":"D","explanation":"Soil with low pH implies an acidic soil. Most micro organisms survive in soils with a normal pH level.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>11","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Chlorosis with characteristic parallel white or yellow streaks observed along the veins of leaves is a deficiency symptom of","images":[],"options":{"A":"potassium","B":"magnesium","C":"phosphorus","D":"sulphur"},"answer":"B","explanation":"Chlorosis with characteristic parallel white or yellow streaks observed along the veins of leaves is a deficiency symptom of magnesium. Magnesium is a key component of chlorophyll, the pigment that gives plants their green color. When a plant is deficient in magnesium, the chlorophyll in its leaves can break down, causing the characteristic yellow or white streaks.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>12","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Use the information below to answer this question  I. Allowing land to fallow  II. Applying organic fertilizer  III. Practising monoculture   IV. Growing legumes.    Which of the following combinations will help to improve soil fertility status?","images":[],"options":{"A":"I, III and IV only","B":"II, III and IV only","C":"I, II and III only","D":"I, II and IV only"},"answer":"D","explanation":"Practising monoculture does not improve soil fertility status rather makes use of it. It is just the planting of one type of crop on a farm land. Legumes help in nitrogen fixation in the soil thereby improving its fertility.  I, II and IV only.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>13","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Use the information below to answer this question  I. Allowing land to fallow  II. Applying organic fertilizer  III. Practising monoculture   IV. Growing legumes.  The spread of diseases and pests can be checked by","images":[],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"C","explanation":"Practising monoculture can help to check the spread of diseases and pests. This is because a single type of crop is grown over a large area for many years in a row, making it easier to manage pests and diseases that are specific to that crop. However, it should be noted that this practice can also lead to an increase in certain types of pests and diseases that are specific to the crop being grown.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>14","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Which of the following statements is not an advantage of drainage? It","images":[],"options":{"A":"removes excess water","B":"supplies moisture for plant growth","C":"reclaims water-logged land and swamps","D":"improves soil structure"},"answer":"B","explanation":"Supplies moisture for plant growth.  Drainage involves removal of excess water on a farmland; therefore it does not supply moisture for plant growth.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>15","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"The problems associated with farm irrigation do not include","images":[],"options":{"A":"high cost of irrigation equipment","B":"increase in soil pH","C":"continuous supply of irrigation water","D":"build up of pests on farms"},"answer":"C","explanation":"The problems associated with farm irrigation do not include continuous supply of irrigation water.  Irrigation is the supply of water to a farm land; this can cause build up of pest and also increase the soil pH, if the water is in excess and it is expensive to construct.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>16","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Which of the following options give the correct sequence of land preparation for planting yam?  I. Burning of trash  II. smashing of undergrowth   III. seed bed preparation   IV.Soil tillage","images":[],"options":{"A":"IV, II, III and I","B":"II, I, IV and III","C":"II, III, I and IV","D":"I, II, III and IV"},"answer":"B","explanation":"The correct sequence of land preparation for planting yam is smashing of undergrowth, burning of trash, soil tillage, and seed bed preparation. Smashing of undergrowth is the first step to clear the land. The trash is then burned to kill pests and diseases. Soil tillage is done to prepare the soil for planting, and finally, the seed bed is prepared for the yam seeds.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>17","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"I. Burning of trash  II. smashing of undergrowth   III. seed bed preparation   IV.Soil tillage   Which of the following practices will enhance loss of soil water?","images":[],"options":{"A":"I and II","B":"II and III","C":"III and IV","D":"I and IV"},"answer":"D","explanation":"Burning of trash and soil tillage can enhance loss of soil water by increasing the temperature of the soil and exposing the soil to the sun and wind, respectively.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>18","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"The most versatile source of farm power in West Africa is","images":[],"options":{"A":"biogas","B":"animal","C":"wind","D":"water"},"answer":"B","explanation":"West Africa still use animal as a source of farm power,which is very versatile. Farm works such as tilling, ridging are still carried out by animals.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>19","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Silos ensure good storage because","images":[],"options":{"A":"they are made of stainless steel","B":"of the air-tight environment created","C":"a lot of produce can be stored at a time","D":"they have high relative humidity"},"answer":"B","explanation":"Silos ensure good storage because of the air-tight environment created.  - Silos are large structures for storing grains.  - Silos are air-tight, preventing air from entering thereby ensuring the good condition of stored grains.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>20","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : AGRICULTURAL MECHANIZATION","question":"Which of the following statements about the advantages of farm mechanization is not true? It","images":[],"options":{"A":"saves labour","B":"improves soil structure","C":"reduces drudgery","D":"increases output"},"answer":"B","explanation":"Farm mechanization does not improve soil structure, rather it destroys it due to the usage of heavy equipments which go deep into the soil.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>21","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The standard length of a Gunter's chain is approximately","images":[],"options":{"A":"20m","B":"25m","C":"35m","D":"40m"},"answer":"A","explanation":"The standard length of a Gunter's chain is approximately 20cm.  It should be noted that Gunter's chain is a measuring instrument 66ft [20.1cm] long; it contains short section connected to the next link by a loop.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>22","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"A farmstead is best described as","images":[],"options":{"A":"animal pens","B":"crop production centre","C":"farm equipment and storage facilities","D":"farmer's abode"},"answer":"D","explanation":"A farmstead is the main house of the farmer and the land that is directly adjacent to the house. It includes the farmer's abode and may also include outbuildings, such as barns or sheds. It does not specifically refer to animal pens, crop production centers, or farm equipment and storage facilities, although these may be part of a larger farm that includes the farmstead.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>23","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"Which of the following process in plants are directly affected by high temperature?  I. Water absorption  II. Photosynthesis  III. Respiration  IV. Photoperiodism","images":[],"options":{"A":"I and II only","B":"I, II and III only","C":"I and IV only","D":"II, III and IV only"},"answer":"B","explanation":"High temperature directly affects water absorption, photosynthesis, and respiration in plants. Water absorption is affected because high temperatures can increase evaporation and transpiration rates, reducing the amount of water available to the plant. Photosynthesis is affected because high temperatures can damage the enzymes that carry out photosynthesis, reducing the plant's ability to produce food. Respiration is affected because it is a temperature-dependent process, and high temperatures can increase the rate of respiration, potentially leading to a net loss of energy for the plant. Photoperiodism, on the other hand, is the physiological reaction of organisms to the length of day or night and is not directly affected by temperature.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>24","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Layering is advantageous because","images":[],"options":{"A":"offspring perform better than their parents","B":"pollination agents abound to ensure its success","C":"possible failure of fertilization is avoided","D":"variability arises in propagates"},"answer":"C","explanation":"Layering involves making a portion of an above-ground stem grow root while still attached to the parent plant and eventually detaches as an independent plant.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>25","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Drying of harvested crops is necessary because it","images":[],"options":{"A":"shortens the length of seed dormancy","B":"reduces moisture content and stores better","C":"cannot be sold to consumers when it is wet","D":"decreases the viability of the crops"},"answer":"B","explanation":"Drying reduces the water/moisture content of a seed thereby slowing down metabolic activities in the seed.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>26","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"Which of the following factors will not influence the yield of crops?","images":[],"options":{"A":"Soil depth and structure","B":"Soil slope and texture","C":"Atmospheric and soil temperature","D":"Wind direction and speed"},"answer":"D","explanation":"Wind direction and speed does not influence the yield of crops, but soil-structure, temperature and texture affect the yield because they determine the type of nutrients that is available for the crop.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>27","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"If the seed rate for guinea corn is 5.6kg per hectare, what will be the amount of seeds required for planting 35 acres of farm land?","images":[],"options":{"A":"40.6kg","B":"78.4kg","C":"196.0kg","D":"784.0kg"},"answer":"B","explanation":"1 hectare = 2.5 acres  If 5.6kg is used for 2.5 acres  x is used for 35 acres  5.6x=2.535  x=5.6 \u00d7 352.5  x = 5.6 \u00d7 14 = 78.4kg","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2007>28","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Delayed harvesting of maize may result in","images":[],"options":{"A":"improvement in the quantity of grains","B":"high incidence of pest infestation","C":"low seed viability","D":"yellow colouration of grains."},"answer":"B","explanation":"Delayed harvesting of maize may result in high incidence of pest infestation. It should be noted that the longer the maize is on its stalk, the move it is infested by pest.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>29","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Tomato plants are primarily staked to","images":[],"options":{"A":"prevent birds from feeding on the fruits","B":"accelerate fruits maturity","C":"raise fruits from the ground","D":"increase crop growth"},"answer":"C","explanation":"Tomato plants are primarily stalked to raise fruits from the ground. If the fruits are left on the ground, decay process sets in and they begin to rotten.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>30","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following crops does not require nursery?","images":[],"options":{"A":"Lycopersion esculentum","B":"Abelmuscus esculentus","C":"Theobroma cacao","D":"Hevea braziliensis"},"answer":"B","explanation":"Okra =  Abelmuscus esculentus does not require nursery; it is planted just few centimetres below the soil surface.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>31","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"An erect tropical perennial grass, which grows to 3 - 6 metres tall and has broad hairy leaves is the","images":[],"options":{"A":"elephant grass","B":"giant star grass","C":"spear grass","D":"gamba grass"},"answer":"A","explanation":"Elephant grass, also known as Pennisetum purpureum, is an erect tropical perennial grass that grows to 3 - 6 metres tall and has broad hairy leaves. It is often used for grazing and as a biofuel crop.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>32","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"Deforestation will eventually lead to","images":[],"options":{"A":"improvement in soil fertility","B":"improvement of soil texture","C":"loss of soil organic matter","D":"increase in soil pH"},"answer":"C","explanation":"Deforestation will eventually lead to loss of soil organic matter. Deforestation is the uncontrolled falling of trees, without planting another one (afforestation). This exposes the soil and leads to washing away and loss of soil organic matter.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>33","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Golden brown lesions on peeled yam tuber indicate infection by","images":[],"options":{"A":"bacteria","B":"virus","C":"fungi","D":"nematode"},"answer":"C","explanation":"Golden brown lesions on peeled yam tuber indicate infection by fungi. Fungi are a type of pathogenic microorganism that can cause diseases in plants. They often cause visible symptoms such as lesions, spots, or discoloration on the plant's tissues.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>34","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"The eradication of mealy bugs is an effective control of","images":[],"options":{"A":"corn smut","B":"swollen shoot of cocoa","C":"groundnut rosette","D":"rice blast"},"answer":"B","explanation":"The eradication of mealy bugs is an effective control of swollen shoot of cocoa. Mealy bugs are pests that can cause significant damage to a variety of plants, including cocoa. They can transmit the virus that causes the swollen shoot disease in cocoa plants. Therefore, controlling mealy bugs can help to prevent this disease.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>35","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"The side effects of the various preventive and control measures of pests and diseases of crops include the following except","images":[],"options":{"A":"improved quality of farm produce","B":"environmental pollution","C":"poisoning of wildlife","D":"disruption of the ecosystem"},"answer":"A","explanation":"The side effects of the various preventive and control measures of pests and diseases of crops do not include improved quality of farm produce.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>36","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"Biological methods of weed control do not include","images":[],"options":{"A":"introducing insects to control weeds","B":"planting crops to compete with the weeds","C":"planting leguminous cover crops","D":"uprooting the weeds"},"answer":"D","explanation":"Biological methods of weed control involve the use of living organisms to control weed growth. This includes introducing insects to control weeds, planting crops to compete with the weeds, and planting leguminous cover crops. Uprooting the weeds is a physical method of weed control, not a biological one.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>37","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"Use the information below to answer this question  Assuming that in sheep, the allele for black coat colour is dominant over that of brown coat colour.    What percentage of the F1 generation will have black coat colour when two heterozygotes are crossed?","images":[],"options":{"A":"100%","B":"75%","C":"50%","D":"25%"},"answer":"B","explanation":"* The allele for black colour is dominant over that of brown coat colour.  * Let B represent the allele for black color.  * Let b represent the allele for brown color.    Phenotypic ratio: Black : Brown = 75% : 25%","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2007>38","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"Use the information below to answer this question  Assuming that in sheep, the allele for black coat colour is dominant over that of brown coat colour.  Crossing a heterozygote black with a homozygote brown will produce","images":[],"options":{"A":"100% brown coat coloured offspring","B":"75% brown coat coloured offspring","C":"50% brown coat coloured offspring","D":"25% brown coat coloured offspring"},"answer":"C","explanation":"Crossing a heterozygote black (Bb) with a homozygous brown (bb) will produce 50% black coat offspring and 50% brown coat offspring.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2007>39","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below shows the alimentary canal of a monogastric animal.     Use it to answer this question    Bile is synthesized in the part labelled","images":["data:image/png;base64,"],"options":{"A":"II","B":"III","C":"IV","D":"VI"},"answer":"D","explanation":"The part labelled VI represents the liver.  Bile is produced in the liver.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2007>40","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below shows the alimentary canal of a monogastric animal.     Use it to answer this question  Absorption of water takes place in the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"IV","D":"V"},"answer":"B","explanation":"The part labelled II represents the intestine   Absorption takes place in the intestine.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2007>41","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Which of the following structures is not connected to the urethra of a bull?","images":[],"options":{"A":"Bladder","B":"Epididymis","C":"Testis","D":"Rectum"},"answer":"D","explanation":"The urethra of a bull is connected to the bladder, epididymis, and testis for the passage of urine and semen. However, it is not connected to the rectum, which is part of the digestive system.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>42","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Ruminants do not normally show deficiency symptoms of vitamin B complex because","images":[],"options":{"A":"the grasses they consume are very rich in the vitamins","B":"they do not need the vitamins","C":"they tolerate the deficiency of these vitamins","D":"the bacteria in their rumen synthesize the vitamins"},"answer":"D","explanation":"Ruminants do not normally show deficiency symptoms of vitamin B complex because the bacteria in their rumen synthesize the vitamins.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>43","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Fluids from the cowper's and prostate glands help in the following except","images":[],"options":{"A":"clearing the urethra of urine traces","B":"provision of nutrients for spermatozoa survival","C":"mixing with spermatozoa to form sperm on ejaculation","D":"maintaining the proper functioning of the testes"},"answer":"D","explanation":"Fluids from the Cowper's and prostrate glands do not help in the maintaining the proper functioning of the testes.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>44","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The gestation period of ewe is","images":[],"options":{"A":"90 days","B":"115 days","C":"131 days","D":"149 days"},"answer":"D","explanation":"The gestation period of a ewe, or female sheep, is approximately 145-149 days, or about five months. This is the period of time between conception and birth.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>45","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The hormone that influences the movement of the pelvic ligaments during parturition in farm animal is known as","images":[],"options":{"A":"relaxin","B":"prolactin","C":"progesterone","D":"oestrogen"},"answer":"A","explanation":"The hormone that influences the movement of the pelvic ligaments during parturition in farm animal is known as relaxin.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>46","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"In order to prevent bulls from eating crops during work, they should be","images":[],"options":{"A":"branded","B":"dehorned","C":"tethered","D":"muzzled"},"answer":"D","explanation":"In order to prevent bulls from eating crops during work, they should be muzzled.  A muzzle is a covering put over the mouth and nose of an animal to prevent the animal from using these parts of the body.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>47","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"In which of the following systems of poultry management can the spread of diseases be kept to a minimum?","images":[],"options":{"A":"Battery cage","B":"Deep litter","C":"Fold","D":"Free range"},"answer":"A","explanation":"The spread of diseases can be kept to a minimum in a battery cage system. In a battery cage system, every bird is confined to its own compartment, hence movement from one bird to another is limited, which consequently reduces the spread of disease.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>48","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A wallow is usually constructed in piggeries to","images":[],"options":{"A":"serve as points for providing drinking water","B":"make draining of pens easier","C":"provide baths for pigs","D":"reduce piglet's mortality during birth"},"answer":"C","explanation":"A wallow is usually constructed in piggery to provide baths for pigs. This helps in thermoregulation.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>49","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following groups of macro-nutrients is a constituents of protein?","images":[],"options":{"A":"Nitrogen, phosphorus and sulphur","B":"Calcium, magnesium and potassium","C":"Magnesium, calcium and phosphorus","D":"Sulphur, magnesium and potassium"},"answer":"A","explanation":"Proteins are made up of amino acids, and these amino acids contain elements such as nitrogen, sulphur, and phosphorus. Therefore, these elements are considered as constituents of proteins. The other options do not contain all the elements that are constituents of proteins.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>50","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following livestock diseases affects the reproductive system?","images":[],"options":{"A":"Mastitis","B":"Brucellosis","C":"Rinderpest","D":"Anthrax"},"answer":"B","explanation":"Brucellosis is a bacterial disease that affects the reproductive organs of livestock, causing infertility, abortions, and reduced milk production. The other diseases listed do not primarily affect the reproductive system. Mastitis affects the mammary glands, Rinderpest is a viral disease affecting many types of tissues, and Anthrax is a bacterial disease affecting mostly the skin, lungs, and intestines.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>51","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"If in a poultry flock, the birds keep passing out green, foul-smelling faeces with nervous symptoms, it shows that the farmer.","images":[],"options":{"A":"has not administered Newcastle disease vaccine","B":"neglected to treat chicks against gumboro disease","C":"is giving the birds protein-deficient diet","D":"is feeding a diet high in calcium"},"answer":"B","explanation":"The symptoms described in the question are indicative of Gumboro disease, also known as Infectious Bursal Disease. This disease affects the immune system of young chickens, causing symptoms such as depression, loss of appetite, and the passing of watery, foul-smelling, greenish faeces. The other options do not match the symptoms described.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>52","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"When a farmer tries to eradicate snails from his pastures, he is attempting to control","images":[],"options":{"A":"ticks","B":"tapeworms","C":"trypanosomiasis","D":"liver flukes"},"answer":"D","explanation":"The first intermediate host of liver fluke parasite is the snail. Hence, by eradicating the snails in the pasture, the farmer is trying to eradicate liverfluke.  It should be noted that the infected snails could drop faeces or contaminate the pasture which increases the tendency of the cattle being infected.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>53","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Cropping in fish farming refers to","images":[],"options":{"A":"stocking fish","B":"processing fish","C":"harvesting fish","D":"feeding"},"answer":"C","explanation":"Cropping in fish farming refers to the process of harvesting fish. This is when the fish are caught and removed from the pond or other farming environment. Therefore, the correct answer is option 3, 'harvesting fish'.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>54","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Fertilizing a fish pond with compost manure would most likely","images":[],"options":{"A":"decrease phytoplankton population and decrease fish yield","B":"decrease phytoplankton population and increase fish yield","C":"increase phytoplankton population and decrease fish yield","D":"increase phytoplankton population and increase fish yield"},"answer":"D","explanation":"Fertilizing a fish pond with compost manure would most likely increase the phytoplankton population and increase fish yield. Phytoplankton are microscopic plants that live in the water column of ponds, lakes, and oceans. They are the base of the aquatic food web, providing food for a wide range of sea creatures including fish. Therefore, increasing the phytoplankton population would provide more food for the fish, leading to an increase in fish yield. Hence, the correct answer is option 4, 'increase phytoplankton population and increase fish yield'.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>55","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"A farmer  harvested 260kg of maize , he sold it at the rate of \u20a65.50 per kg. He made a profit of \u20a6430.Calculate the production cost of maize per kg","images":[],"options":{"A":"N4.05","B":"N3.85","C":"N3.75","D":"N3.65"},"answer":"B","explanation":"Total mass of harvested maize = 260kg   Selling price/kg = \u20a65.50/kg  Profit = \u20a6430  Recall:   Profit = Selling price - Cost price --------------- (i)  Total Selling Price (for 260kg mass) = 260 \u00d7 5.5 = \u20a61,430  Cost price = \u20a61430 - \u20a6430 (Selling Price - Profit)  \u21d2 \u20a61000 for 260kg  For1kg,costprice=1000260=\u20a63.85kg","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2007>56","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"A farmer  harvested 260kg of maize , he sold it at the rate of \u20a65.50 per kg. He made a profit of \u20a6430.Calculate the production cost of maize per kg  Determine the percentage profit per kg of maize sold.","images":[],"options":{"A":"35%","B":"40%","C":"43%","D":"52%"},"answer":"C","explanation":"%profitperkg=ProfitCost price\u00d7100  =\u20a6430\u20a61000\u00d7100=43%","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2007>57","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"The demand for agricultural produce is generally","images":[],"options":{"A":"elastic","B":"inelastic","C":"unitary","D":"static"},"answer":"B","explanation":"The demand for agricultural produce is generally inelastic. This is because the quantity demanded does not change significantly with changes in price. This is due to the fact that agricultural produce are basic necessities, and people need to consume them regardless of the price.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>58","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"Agricultural credits should be put to the following uses except","images":[],"options":{"A":"purchase of inputs","B":"meeting family needs","C":"improvement of structures","D":"adoption of innovations"},"answer":"B","explanation":"Agricultural credits are funds provided to farmers to support their farming activities. These credits should be used for purposes that directly enhance the productivity and profitability of the farm such as the purchase of inputs, improvement of structures, and adoption of innovations. Using agricultural credits to meet family needs is not a productive use of the funds and does not contribute to the growth of the farm. Therefore, the correct answer is option 2.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>59","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"Which of the following statements is not true about the profit and loss account of a farm?","images":[],"options":{"A":"It is prepared at the end of business period usually a year","B":"All expenses and purchases are listed on the right-hand side","C":"All expenses and purchases are listed on the left-hand side","D":"all receipts and sales are listed on the right-hand side"},"answer":"C","explanation":"A profit and loss account, also known as an income statement, is a financial statement that summarizes the revenues, costs, and expenses incurred during a specific period of time. In a typical profit and loss account, all expenses and purchases are listed on the right-hand side, while all receipts and sales are listed on the left-hand side. Therefore, the statement 'All expenses and purchases are listed on the left-hand side' is not true, making option 3 the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2007>60","subject":"Agricultural Science","year":"2007","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"Agricultural education programmed for rural youth will reduce the","images":[],"options":{"A":"rate of adoption of innovations","B":"population of youth in rural areas","C":"age at which youth will venture into family life","D":"dependency of youth on parents"},"answer":"D","explanation":"Agricultural education programmes for rural youth will reduce the rate of dependency of youth on parents.","marks":"1","difficulty":"2"}];